 39→/* Pre-allocated snapshot buffers (~350KB each, ~1MB total) */
 40→game_state_snapshot parity_snap_before;
 41→game_state_snapshot parity_snap_after_ocaml;
 42→game_state_snapshot parity_snap_after_c;
 43→
 44→/* Runtime configuration */
 45→static int parity_initialized = 0;
 46→static int parity_assert_on_diverge = 0;
 47→static FILE *parity_log_file = NULL;
 48→static int parity_total_divergences = 0;
 49→
 50→void parity_init(void)
 51→{
 52→	if (parity_initialized) return;
 53→	parity_initialized = 1;
 54→
 55→	const char *assert_env = getenv("OX_PARITY_ASSERT");
 56→	if (assert_env && atoi(assert_env))
 57→		parity_assert_on_diverge = 1;
 58→
 59→	const char *log_env = getenv("OX_PARITY_LOG");
 60→	if (log_env && log_env[0]) {
 61→		parity_log_file = fopen(log_env, "w");
 62→		if (!parity_log_file)
 63→			fprintf(stderr, "PARITY: failed to open log file '%s'\n", log_env);
 64→	}
 65→
 66→	fprintf(stderr, "PARITY: initialized (assert=%d, log=%s)\n",
 67→		parity_assert_on_diverge,
 68→		log_env ? log_env : "stderr");
 69→}
 70→
 71→/* Helper: write to both stderr and optional log file */
 72→static void parity_log(const char *fmt, ...)
 73→{
 74→	va_list ap;
 75→	va_start(ap, fmt);
 76→	vfprintf(stderr, fmt, ap);
 77→	va_end(ap);
 78→
 79→	if (parity_log_file) {
 80→		va_start(ap, fmt);
 81→		vfprintf(parity_log_file, fmt, ap);
 82→		va_end(ap);
 83→		fflush(parity_log_file);
 84→	}
 85→}
 86→
 87→void parity_snapshot(game_state_snapshot *dst)
 88→{
 89→	int n_objects = Highest_object_index + 1;
 90→	if (n_objects > PARITY_MAX_OBJECTS)
 91→		n_objects = PARITY_MAX_OBJECTS;
 92→	if (n_objects > 0) {
 93→		memcpy(dst->objects, Objects, n_objects * sizeof(object));
 94→		memcpy(dst->ai_local_info, Ai_local_info, n_objects * sizeof(ai_local));
 95→	}
 96→
 97→	memcpy(dst->players, Players, PARITY_MAX_PLAYERS * sizeof(player));
 98→
 99→	int n_walls = Num_walls;
100→	if (n_walls > PARITY_MAX_WALLS)
101→		n_walls = PARITY_MAX_WALLS;
102→	if (n_walls > 0)
103→		memcpy(dst->walls, Walls, n_walls * sizeof(wall));
104→
105→	/* Save per-segment object list heads */
106→	int n_segs = Highest_segment_index + 1;
107→	if (n_segs > PARITY_MAX_SEGMENTS)
108→		n_segs = PARITY_MAX_SEGMENTS;
109→	for (int i = 0; i < n_segs; i++)
110→		dst->seg_objects[i] = Segments[i].objects;
111→	dst->highest_segment_index = Highest_segment_index;
112→
113→	dst->rand_state = P_Rand_get_state();
114→	dst->highest_object_index = Highest_object_index;
115→	dst->player_is_dead = Player_is_dead;
116→	dst->player_exploded = Player_exploded;
117→	dst->overall_agitation = Overall_agitation;
118→	dst->num_walls = Num_walls;
119→	dst->frame_time = FrameTime;
120→	dst->game_time = GameTime;
121→	dst->frame_count = FrameCount;
122→}
123→
124→void parity_restore(const game_state_snapshot *src)
125→{
126→	int n_objects = src->highest_object_index + 1;
127→	if (n_objects > PARITY_MAX_OBJECTS)
128→		n_objects = PARITY_MAX_OBJECTS;
129→	if (n_objects > 0) {
130→		memcpy(Objects, src->objects, n_objects * sizeof(object));
131→		memcpy(Ai_local_info, src->ai_local_info, n_objects * sizeof(ai_local));
132→	}
133→
134→	memcpy(Players, src->players, PARITY_MAX_PLAYERS * sizeof(player));
135→
136→	int n_walls = src->num_walls;
137→	if (n_walls > PARITY_MAX_WALLS)
138→		n_walls = PARITY_MAX_WALLS;
139→	if (n_walls > 0)
140→		memcpy(Walls, src->walls, n_walls * sizeof(wall));
141→
142→	Highest_object_index = src->highest_object_index;
143→	Player_is_dead = src->player_is_dead;
144→	Player_exploded = src->player_exploded;
145→	Overall_agitation = src->overall_agitation;
146→	Num_walls = src->num_walls;
147→	FrameTime = src->frame_time;
148→	GameTime = src->game_time;
149→	FrameCount = src->frame_count;
150→
151→	P_Rand_set_state(src->rand_state);
152→
153→	/* Restore per-segment object list heads */
154→	int n_segs = src->highest_segment_index + 1;
155→	if (n_segs > PARITY_MAX_SEGMENTS)
156→		n_segs = PARITY_MAX_SEGMENTS;
157→	for (int i = 0; i < n_segs; i++)
158→		Segments[i].objects = src->seg_objects[i];
159→}
