307→static int compare_player(const player *pa, const player *pb, int idx)
308→{
309→	int divergences = 0;
310→	int a_val, b_val;
311→	char prefix[64];
312→	snprintf(prefix, sizeof(prefix), "Players[%d]", idx);
313→
314→	CMP_FIELD(prefix, flags, pa->flags, pb->flags);
315→	CMP_FIELD(prefix, energy, pa->energy, pb->energy);
316→	CMP_FIELD(prefix, shields, pa->shields, pb->shields);
317→	CMP_FIELD(prefix, lives, pa->lives, pb->lives);
318→	CMP_FIELD(prefix, laser_level, pa->laser_level, pb->laser_level);
319→	CMP_FIELD(prefix, score, pa->score, pb->score);
320→	CMP_FIELD(prefix, primary_weapon_flags, pa->primary_weapon_flags, pb->primary_weapon_flags);
321→	CMP_FIELD(prefix, secondary_weapon_flags, pa->secondary_weapon_flags, pb->secondary_weapon_flags);
322→	CMP_FIELD(prefix, cloak_time, pa->cloak_time, pb->cloak_time);
323→	CMP_FIELD(prefix, invulnerable_time, pa->invulnerable_time, pb->invulnerable_time);
324→	CMP_FIELD(prefix, hostages_on_board, pa->hostages_on_board, pb->hostages_on_board);
325→
326→	for (int i = 0; i < 10; i++) { /* MAX_PRIMARY_WEAPONS */
327→		if (pa->primary_ammo[i] != pb->primary_ammo[i]) {
328→			parity_log("  %s.primary_ammo[%d]: OCaml=%u C=%u\n", prefix, i,
329→				pa->primary_ammo[i], pb->primary_ammo[i]);
330→			divergences++;
331→		}
332→	}
333→	for (int i = 0; i < 10; i++) { /* MAX_SECONDARY_WEAPONS */
334→		if (pa->secondary_ammo[i] != pb->secondary_ammo[i]) {
335→			parity_log("  %s.secondary_ammo[%d]: OCaml=%u C=%u\n", prefix, i,
336→				pa->secondary_ammo[i], pb->secondary_ammo[i]);
337→			divergences++;
338→		}
339→	}
340→
341→	return divergences;
342→}
