198→int ox_replayer_apply_frame(void)
199→{
200→	if (!replaying_active)
201→		return -1;
202→
203→	if (frames_replayed >= replay_header.num_frames)
204→		return -1;
205→
206→	/* Refill buffer if needed */
207→	if (buffer_pos >= buffer_count) {
208→		if (refill_buffer() == 0)
209→			return -1;
210→	}
211→
212→	const ox_frame_record *rec = &replay_buffer[buffer_pos];
213→	buffer_pos++;
214→	frames_replayed++;
215→
216→	/* Override FrameTime */
217→	FrameTime = rec->frame_time;
218→
219→	/* Override RNG state */
220→	P_Rand_set_state(rec->rand_state);
221→
222→	/* Override Controls */
223→	Controls.pitch_time = rec->ctrl_pitch_time;
224→	Controls.vertical_thrust_time = rec->ctrl_vertical_thrust_time;
225→	Controls.heading_time = rec->ctrl_heading_time;
226→	Controls.sideways_thrust_time = rec->ctrl_sideways_thrust_time;
227→	Controls.bank_time = rec->ctrl_bank_time;
228→	Controls.forward_thrust_time = rec->ctrl_forward_thrust_time;
229→	Controls.rear_view_down_count = rec->ctrl_rear_view_down_count;
230→	Controls.rear_view_down_state = rec->ctrl_rear_view_down_state;
231→	Controls.fire_primary_down_count = rec->ctrl_fire_primary_down_count;
232→	Controls.fire_primary_state = rec->ctrl_fire_primary_state;
233→	Controls.fire_secondary_state = rec->ctrl_fire_secondary_state;
234→	Controls.fire_secondary_down_count = rec->ctrl_fire_secondary_down_count;
235→	Controls.fire_flare_down_count = rec->ctrl_fire_flare_down_count;
236→	Controls.drop_bomb_down_count = rec->ctrl_drop_bomb_down_count;
237→	Controls.automap_down_count = rec->ctrl_automap_down_count;
238→	Controls.automap_state = rec->ctrl_automap_state;
239→#ifdef BUILD_DESCENT2
240→	Controls.afterburner_state = rec->ctrl_afterburner_state;
241→	Controls.cycle_primary_count = rec->ctrl_cycle_primary_count;
242→	Controls.cycle_secondary_count = rec->ctrl_cycle_secondary_count;
243→	Controls.headlight_count = rec->ctrl_headlight_count;
244→#endif
245→
246→	return 0;
247→}
