249→void ox_replayer_log_state(void)
250→{
251→	if (!state_log)
252→		return;
253→
254→	/* Write frame number */
255→	uint32_t frame = frames_replayed;
256→	fwrite(&frame, sizeof(frame), 1, state_log);
257→
258→	/* Write key game state: objects up to Highest_object_index */
259→	int n_obj = Highest_object_index + 1;
260→	if (n_obj > MAX_OBJECTS) n_obj = MAX_OBJECTS;
261→
262→	int32_t n = n_obj;
263→	fwrite(&n, sizeof(n), 1, state_log);
264→	if (n_obj > 0) {
265→		fwrite(Objects, sizeof(object), n_obj, state_log);
266→		fwrite(Ai_local_info, sizeof(ai_local), n_obj, state_log);
267→	}
268→
269→	/* Write players */
270→	fwrite(Players, sizeof(player), MAX_PLAYERS, state_log);
271→
272→	/* Write globals */
273→	int32_t globals[5];
274→	globals[0] = Player_is_dead;
275→	globals[1] = Player_exploded;
276→	globals[2] = Overall_agitation;
277→	globals[3] = Highest_object_index;
278→	globals[4] = (int32_t)P_Rand_get_state();
279→	fwrite(globals, sizeof(globals), 1, state_log);
280→}
