282→void ox_replayer_close(void)
283→{
284→	if (replay_file) {
285→		fclose(replay_file);
286→		replay_file = NULL;
287→	}
288→	if (state_log) {
289→		fclose(state_log);
290→		state_log = NULL;
291→	}
292→	if (initial_snapshot) {
293→		free(initial_snapshot);
294→		initial_snapshot = NULL;
295→	}
296→	replaying_active = 0;
297→
298→	fprintf(stderr, "OX_REPLAY: replay closed (%u frames replayed)\n", frames_replayed);
299→}
