		int32_t result[43];
		cd_ox_do_ai_frame_d1(
			ai_state, 43,
			rinfo, 29,
			FrameTime, FrameCount, GameTime,
			Game_mode, Difficulty_level,
			Overall_agitation, Player_is_dead, Player_exploded,
			Players[Player_num].flags,
